input[data-invalid],
  .#{$prefix}--number[data-invalid] .#{$prefix}--number__input-wrapper,
  .#{$prefix}--number__input-wrapper--warning,
  .#{$prefix}--date-picker-input__wrapper,
  .#{$prefix}--date-picker-input__wrapper--warn,
  .#{$prefix}--date-picker-input__wrapper--invalid,
  .#{$prefix}--time-picker--invalid,
  .#{$prefix}--time-picker--warning,
  .#{$prefix}--text-input__field-wrapper[data-invalid],
  .#{$prefix}--text-input__field-wrapper--warning,
  .#{$prefix}--text-input__field-wrapper--warning > .#{$prefix}--text-input,
  .#{$prefix}--text-area__wrapper[data-invalid],
  .#{$prefix}--text-area__wrapper--warn,
  .#{$prefix}--select-input__wrapper[data-invalid],
  .#{$prefix}--select--warning .#{$prefix}--select-input__wrapper,
  .#{$prefix}--time-picker[data-invalid],
  .#{$prefix}--list-box[data-invalid],
  .#{$prefix}--list-box--warning {
    ~ .#{$prefix}--form-requirement {
      display: block;
      overflow: visible;
      font-weight: 400;
      max-block-size: convert.to-rem(200px);
    }
  }

// We use this function only in variables.scss because recursive imports are not allowed in Sass anymore.

@function color-contrast-variables($background, $color-contrast-dark, $color-contrast-light, $white, $black, $min-contrast-ratio) {
  $foregrounds: $color-contrast-light, $color-contrast-dark, $white, $black;
  $max-ratio: 0;
  $max-ratio-color: null;

  @each $color in $foregrounds {
    $contrast-ratio: contrast-ratio($background, $color);
    @if $contrast-ratio >= $min-contrast-ratio {
      @return $color;
    } @else if $contrast-ratio > $max-ratio {
      $max-ratio: $contrast-ratio;
      $max-ratio-color: $color;
    }
  }

  @warn "Found no color leading to #{$min-contrast-ratio}:1 contrast ratio against #{$background}...";

  @return $max-ratio-color;
}

&[disabled] {
  cursor: not-allowed;
  user-select: none;

  ~ label .slds-visual-picker__body,
  ~ label .slds-visual-picker__text {
    color: var(--slds-g-color-neutral-base-50, #{$color-text-input-disabled});
  }

  ~ label .slds-visual-picker__figure {
    border-color: var(--slds-g-color-border-base-1, #{$color-border-input-disabled});
    background-color: var(--slds-g-color-neutral-base-95, #{$color-background-input-disabled});
    box-shadow: none;

    &:hover {
      cursor: not-allowed;
      user-select: none;
      box-shadow: none;
    }
  }

  ~label .slds-visual-picker__figure .slds-icon {
    fill: var(--slds-g-color-neutral-base-80, #{$color-text-icon-default-disabled});
  }

}
